customHandlers.d_gor42y:
function(ctx) {
  // ========== 请根据实际站点修改此函数 ==========
  // 当前为示例：从 vod_id 拆分获取信息（央视格式）
  // 您需要修改为请求详情接口，并构造 vod_play_url（格式：剧集名称$播放ID#剧集名称$播放ID...）
  var parts = ctx.vodId.split('###');
  if (parts.length < 3) return { list: [] };
  var title = parts[1];
  var lastVideo = parts[2];
  var logo = parts[3];
  if (lastVideo === '_') return { list: [] };
  var infoUrl = 'https://api.cntv.cn/video/videoinfoByGuid?guid=' + lastVideo + '&serviceId=tvcctv';
  var infoJson = JSON.parse(req(infoUrl).content);
  if (!infoJson.ctid) return { list: [] };
  var topicId = infoJson.ctid;
  var channel = infoJson.channel || '';
  var listUrl = 'https://api.cntv.cn/NewVideo/getVideoListByColumn?id=' + topicId + '&d=&p=1&n=100&sort=desc&mode=0&serviceId=tvcctv&t=json';
  var listJson = JSON.parse(req(listUrl).content);
  var videoList = [];
  var videos = listJson.data && listJson.data.list ? listJson.data.list : [];
  for (var i = 0; i < videos.length; i++) {
    var video = videos[i];
    var playId = video.pid || video.vid || video.guid;
    if (playId) videoList.push(video.title + '$' + playId);
  }
  if (videoList.length === 0) return { list: [] };
  var vod = {
    vod_id: ctx.vodId,
    vod_name: title,
    vod_pic: logo,
    type_name: channel,
    vod_play_from: '示例站点',
    vod_play_url: videoList.join('#')
  };
  return { list: [vod] };
}

customHandlers.p_hlax4o:
function(ctx) {
  // ========== 请根据实际站点修改此函数 ==========
  // 当前为示例：根据传入的 id 请求播放地址
  var pid = ctx.id;
  var url = 'https://vdn.apps.cntv.cn/api/getHttpVideoInfo.do?pid=' + pid;
  var json = JSON.parse(req(url).content);
  var hls = json.hls_url || '';
  return { parse: 0, playUrl: '', url: hls };
}

customHandlers.h_txo0a6:
function(ctx) {
  var url = "https://api.cntv.cn/lanmu/columnSearch?p=1&n=20&serviceId=tvcctv&t=json";
  var resp = req(url);
  var json = JSON.parse(resp.content);
  var data = json;
data = data["response"];
data = data["docs"];
  if (!Array.isArray(data)) data = [];
  var result = [];
  for (var i = 0; i < data.length; i++) {
    var item = data[i];
    var vod = {
      vod_id: item["id"] || "",
      vod_name: item["title"] || "无标题",
      vod_pic: ""
    };
    result.push(vod);
  }
  return result;
}
